  ('social-worker-moex-01861', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據Papell和Rothman（1962）的團體工作實務模型分類，｢失智症家屬互助團體」屬於下列何者？', '["社會目標模型（social goals model）", "治療模型（remedial model）", "交互模型（reciprocal model）", "發展途徑（development approach）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
