  ('social-worker-moex-01868', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者可以說明個案紀錄的功能？', '["依據紀錄內容有不同的紀錄要點與格式", "紀錄內容能成為教學與研究的重要資料", "依據服務過程，應該有不同的紀錄格式", "在司法的要求下方得以提供紀錄的內容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01869', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '根據Jonathan Bradshaw的需求分類，「透過問卷調查瞭解社區居民對於托育服務的需要」，屬於下列那 一種？', '["規範性需求（normal need）", "感覺性需求（felt need）", "表達性需求（expressed need）", "比較性需求（comparative need）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01870', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於美國學者克里茲曼與麥克奈（Kretzmann & Mcknight）在1993年提出的「以資產為基礎的社區發展」 （Asset-Based Community Development, ABCD）模式，下列敘述何者錯誤？', '["以「社區問題與需求」為取向", "以夥伴關係來推動", "社區資產包含居民、硬體、組織和生活", "以社區內部為焦點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01871', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於「福利社區化」的敘述，以下何者錯誤？', '["根據「推動社會福利社區化實施要點」的內容，更名為「福利服務社區化」更為名實相符", "服務可近性、社會整合以及福利社會的具體實踐是其目的", "福利社區化包含了在社區中服務（service in the community）以及由社區來服務（service by the community）兩大意涵", "政府80年代以來的社會福利政策之一，參酌社區照顧的理念，希望社區組織成為「由社區照顧」的服 務提供者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01872', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於Rothman所提出的社區工作模式，下列何者說法正確？', '["社工員在社會行動的工作模式裡的角色是非主導性的輔助者", "社會計畫模式是以公眾利益為依歸，所以是由下而上的改變", "社會行動模式所使用的抗議性行動包含有公民抗命、杯葛等", "社區居民在社區發展的模式裡，是促成改變的重要媒介之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01873', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於社區工作的實踐原則，以下說法何者正確？', '["為了達成民主及理性的社區行動，社會工作者應讓不同年齡層居民都能一人一票參與社區事務決定", "社會工作者應儘可能地讓社區內的不同群體都獲得參與的機會，才能達成廣泛性和包容性參與原則", "社會工作者要能尊重社區居民的自我決定，即使該決定對社區不利，社會工作者也不應該介入干涉", "所謂的實踐原則指的是社會工作者在執行工作時要遵守的規則，與社會工作者的工作準則是不同的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01874', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那個選項內容均為個案工作開案階段要處理的工作項目？①確認案主問題與機構服務相符  ②查', '["進行開案會談", "簽訂服務契約  ⑤連結案主所需要的資源  ⑥瞭解案主的服務 期待", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01875', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於個案工作的資料蒐集和評估（assessment）階段，下列何者敘述錯誤？', '["社工員和案主所進行的會談是蒐集資料很重要的方式", "此階段的評估結果涉及到處遇計畫擬定，不可以變更", "為了蒐集資料，可能需要到案主的生活場域進行訪視", "社工員所繪製的家系圖、生態圖都是幫助評估的工具"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01876', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'McLeod和Meyer在1967年曾提出十組社會工作專業的價值衝突，下列何者敘述正確？', '["相對、實用論或文化決定論之間的衝突", "個人獨立或團體責任之間的衝突", "重視過程或強調結果之間的衝突", "個人本能論或傳統主義之間的衝突"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01877', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作非常重視專業關係，請找出社會工作專業關係錯誤的描述：', '["指的是社工員和案主之間相互影響的情緒狀態", "社工員對案主的接納度有助於正向關係的建立", "社工員和案主在此關係中應該是一種夥伴關係", "是同時滿足案主和社工員自身需求的服務基礎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01878', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於次團體（subgroup），以下敘述何者錯誤？', '["次團體的形成表示團體不能迎合需求", "團體中的成員會因情感連結和利益上的結盟而形成各個次團體", "次團體的形成在治療性團體特別能發揮效用", "次團體的吸引力過強，可能導致團體分裂或瓦解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01879', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Perlman（1973）認為問題解決學派（Problem-solving Approach）的社會個案工作包含四個重要元素，簡 稱4P，以下何者錯誤？', '["計畫（plan）", "個人（a person）", "機構（a place）", "問題（problems）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01880', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在個案工作中，對案主提供協助之前，必須對個人進行評估，下列何者的陳述錯誤？', '["因為人和環境交互影響，所以個人評估也要包含環境面向", "案主說謊、辯解、責怪他人等防衛性反應會影響評估結果", "外貌是重要的訊息，可以決定某些協助對象的需求或類型", "在進行評估時，應對特殊需求的個案提供參與評估的機會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01881', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作常需要面對非自願案主，在與其會談時要注意的是：', '["強調社工員對案主的社會控制權力", "告知案主，社工員在保密上的限制", "尊重案主的自我決定權不加以干涉", "不花過多時間給沒有改變意願案主"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01882', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是團體方案產生的原因？', '["基於案主的需求", "考量社區的需求", "機構的服務使命", "社工員自己的需求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01883', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對任務中心的陳述是正確的？', '["是一種短期處遇模式，處遇期不多於4-8週的期程", "不適合用來協助案主解決其社會關係不滿足的問題", "任務指的是案主為緩和問題的嚴重性所採取的行動", "在處遇上，會運用嚴謹的實務架構提供協助給案主"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01884', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列對個案工作訪視的描述，那些是正確的？①是為了瞭解或促進案主適應的相關情況而使用的方法之', '["像是病人因為都在醫院獲得協助，所以不用進行家庭訪視", "社工員進行訪視時，也必須要考量 到自己的人身安全風險", "為了瞭解案主的真實情況，社工員要安排出其不意地訪視  ⑤家庭訪視的焦 點雖是在家庭，也要瞭解其所在的社區環境  ⑥社工員進行訪視時，要選擇類似會談室的場合進行訪視", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01885', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者對於危機調適模式概念和運用的陳述正確？', '["小學轉換國中就讀階段，就可能產生情境性危機（situational crisis）", "和優勢觀點一致，認為案主有能力積極參與處遇", "危機調適可以運用在天災和角色執行困難的議題", "危機是指人無法處理並出現身心狀態失衡的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "c811122112d3", "answer_pdf_sha1": "0925fb328d2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
